var rate = parseFloat(perStreamRate);
    var gross = streams * rate;
    var share = gross * (labelSplit / 100);
    var totalStreams = 0;
    var monthlyStreams = streams;
    var growthFactor = 1 + (monthlyGrowth / 100);
    for (var i = 0; i < months; i++) {
      totalStreams += monthlyStreams;
      monthlyStreams = Math.round(monthlyStreams * growthFactor);
    }
    var projRev = totalStreams * rate * (labelSplit / 100);
    var monthlyAvgVal = projRev / months;
    document.getElementById('currentRevenue').textContent = '$' + gross.toFixed(2);
    document.getElementById('yourShare').textContent = '$' + share.toFixed(2);
    document.getElementById('projectedStreams').textContent = totalStreams.toLocaleString();
    document.getElementById('projectedRevenue').textContent = '$' + projRev.toFixed(2);
    document.getElementById('monthlyAvg').textContent = '$' + monthlyAvgVal.toFixed(2) + '/mo';

var adImpressions = monthlyViews * (adRate / 100);
    var grossMonthly = adImpressions * cpm / 1000;
    var creatorShare = parseFloat(revSharePct) / 100;
    var creatorMonthly = grossMonthly * creatorShare;
    var rpmVal = monthlyViews > 0 ? (creatorMonthly / monthlyViews * 1000) : 0;
    var totalRev = 0;
    var views = monthlyViews;
    var gf = 1 + (growthRate / 100);
    for (var i = 0; i < months; i++) {
      totalRev += (views * (adRate / 100) * cpm / 1000) * creatorShare;
      views = Math.round(views * gf);
    }
    var dailyAvgVal = creatorMonthly / 30;
    document.getElementById('grossRevenue').textContent = '$' + grossMonthly.toFixed(2);
    document.getElementById('creatorRevenue').textContent = '$' + creatorMonthly.toFixed(2);
    document.getElementById('rpm').textContent = '$' + rpmVal.toFixed(2);
    document.getElementById('annualProjection').textContent = '$' + totalRev.toFixed(2);
    document.getElementById('dailyAvg').textContent = '$' + dailyAvgVal.toFixed(2) + '/day';

var baseFees = {
      tv:    {indie: 500,  mid: 2500,  major: 10000},
      film:  {indie: 1000, mid: 5000,  major: 25000},
      commercial: {indie: 1500, mid: 7500, major: 30000},
      social: {indie: 100, mid: 500,   major: 2000},
      podcast: {indie: 50, mid: 250,   major: 1000},
      game:  {indie: 750,  mid: 3000,  major: 15000}
    };
    var base = baseFees[usageType][productionTier];
    var durationMult = duration > 60 ? 1.5 : (duration > 15 ? 1.0 : 0.75);
    base = base * durationMult;
    var territoryMult = {local: 0.5, national: 1.0, worldwide: 2.0};
    var terrAdj = base * territoryMult[territory] - base;
    var withTerritory = base + terrAdj;
    var exclAdj = exclusivity === 'exclusive' ? withTerritory : 0;
    var perTrack = withTerritory + exclAdj;
    var total = perTrack * tracks;
    document.getElementById('baseFee').textContent = '$' + base.toFixed(0);
    document.getElementById('territoryAdj').textContent = (terrAdj >= 0 ? '+$' : '-$') + Math.abs(terrAdj).toFixed(0);
    document.getElementById('exclusivityAdj').textContent = exclAdj > 0 ? '+$' + exclAdj.toFixed(0) : '$0';
    document.getElementById('perTrackTotal').textContent = '$' + perTrack.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('grandTotal').textContent = '$' + total.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');

var interfaces = {bedroom: 100, prosumer: 350, pro: 1200};
    var mics = {bedroom: 100, prosumer: 500, pro: 2000};
    var monitors = {bedroom: 150, prosumer: 500, pro: 1500};
    var treatments = {none: 0, basic: 200, full: 1500};
    var daws = {free: 0, mid: 200, pro: 550};
